import React, { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import api from "../../api/axios"; // <-- use your api instance

const AddAppointment = () => {
  const navigate = useNavigate();
const [appointment, setAppointment] = useState({
  lead: "",
  vehicle: "",
  appointmentType: "viewing",
  date: "",
  time: "",
  notes: "",
  status: "scheduled",
});
  const [leads, setLeads] = useState([]);
  const [vehicles, setVehicles] = useState([]);

useEffect(() => {
  const fetchData = async () => {
    try {
      const [leadsRes, vehiclesRes] = await Promise.all([
        api.get("/leads"),
        api.get("/vehicles"),
      ]);
      setLeads(leadsRes.data);
      setVehicles(vehiclesRes.data.filter(v => v.status === "available"));
    } catch (err) {
      alert(err.response?.data?.message || "Failed to load leads/vehicles");
    }
  };
  fetchData();
}, []);

  const handleChange = (e) => {
    setAppointment({ ...appointment, [e.target.name]: e.target.value });
  };

const handleSubmit = async (e) => {
  e.preventDefault();
  try {
    await api.post("/appointments/add", appointment);
    alert("Appointment added!");
    navigate("/appointments");
  } catch (err) {
    alert(err.response?.data?.message || "Error adding appointment");
  }
};

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">Add Appointment</div>
          <div className="pageSub">Schedule a new customer appointment</div>
        </div>
      </div>

      <div className="card cardPad" style={{ maxWidth: 580, margin: "32px auto" }}>
        <form onSubmit={handleSubmit}>
          <label className="label">Lead</label>
          <select
            className="select"
            name="lead"
            value={appointment.lead}
            onChange={handleChange}
            required
            style={{ marginBottom: 16 }}
          >
            <option value="">Select Lead</option>
            {leads.map((l) => <option key={l._id} value={l._id}>{l.name}</option>)}
          </select>

          <label className="label">Vehicle</label>
          <select
            className="select"
            name="vehicle"
            value={appointment.vehicle}
            onChange={handleChange}
            required
            style={{ marginBottom: 16 }}
          >
            <option value="">Select Vehicle</option>
            {vehicles.map((v) => <option key={v._id} value={v._id}>{v.brand} {v.type || v.model}</option>)}
          </select>

          <label className="label">Date</label>
          <input
            className="input"
            type="date"
            name="date"
            value={appointment.date}
            onChange={handleChange}
            required
          />

          <label className="label">Time</label>
          <input
            className="input"
            type="time"
            name="time"
            value={appointment.time}
            onChange={handleChange}
            required
          />

          <label className="label">Type</label>
          <select
            className="select"
            name="appointmentType"
            value={appointment.appointmentType}
            onChange={handleChange}
            style={{ marginBottom: 16 }}
          >
            <option value="viewing">Viewing</option>
            <option value="test_drive">Test Drive</option>
            <option value="follow_up">Follow Up</option>
          </select>

          <label className="label">Status</label>
          <select
            className="select"
            name="status"
            value={appointment.status}
            onChange={handleChange}
            style={{ marginBottom: 16 }}
          >
            <option value="scheduled">Scheduled</option>
            <option value="completed">Completed</option>
            <option value="cancelled">Cancelled</option>
          </select>

          <label className="label">Notes</label>
          <textarea
            className="textarea"
            name="notes"
            value={appointment.notes}
            onChange={handleChange}
            placeholder="Interaction notes"
            rows={3}
          />

          <button type="submit" className="btn btnPrimary" style={{ width: "100%", marginTop: 8 }}>
            Save Appointment
          </button>
        </form>
      </div>
    </div>
  );
};

export default AddAppointment;
